{
    "affiliations": [],
    "keywords_raw": ["convex optimization", "primal-dual averaging", "optimality certificate", "non-asymptotic convergence", "accelerated rates", "zero-sum matrix games", "Fisher markets", "gradient extrapolation"],
    "keywords_normalized": ["convex optimization", "primal-dual methods", "convergence analysis", "game theory", "market dynamics", "acceleration"],
    "zh": {
        "tldr": "本文提出基于原始-对偶平均的算法，为凸优化问题提供可计算的加速最优性证书保证。",
        "motivation": "凸优化中通常使用原始间隙衡量最优性，但该指标在实践中难以计算。需要一种可计算的最优性证书并提供非渐近收敛保证。",
        "method": "分析基于单平均、双平均和三平均的原始-对偶平均方法，建立证书复杂度界限，并通过零和矩阵博弈与Fisher市场模型解释结果。",
        "result": "单平均方法获得$\tilde{O}(\varepsilon^{-1})$证书复杂度，三平均方法实现加速的$\tilde{O}(\varepsilon^{-1/2})$复杂度，并建立了原始-对偶算法对应关系。",
        "help_to_user": "为凸优化问题提供可计算的最优性证书和加速收敛保证，适用于需要可验证解的优化场景。",
        "idea_spark": {
            "transferable": "原始-对偶平均框架可迁移至博弈论和市场动态分析。",
            "idea": "通过多平均机制平衡原始与对偶变量的不对称性以实现加速。",
            "risk": "双平均方法虽保持对称性但失去证书保证，需三平均恢复收敛性。",
            "inspiration": "将梯度外推法解释为对偶空间的三平均加速方法，建立算法对应关系。"
        }
    },
    "en": {
        "tldr": "This paper proposes primal-dual averaging algorithms that provide computable accelerated optimality certificates for convex optimization.",
        "motivation": "Convex optimization typically uses primal gap for optimality, but this quantity is often unavailable in practice. A computable optimality certificate with non-asymptotic convergence guarantees is needed.",
        "method": "Analyze primal-dual averaging methods based on one, two, and three averages, establish certificate complexity bounds, and interpret results through zero-sum matrix games and Fisher markets.",
        "result": "One-average methods achieve $\tilde{O}(\varepsilon^{-1})$ certificate complexity, while three-average methods achieve accelerated $\tilde{O}(\varepsilon^{-1/2})$ complexity, with primal-dual algorithm correspondences established.",
        "help_to_user": "Provides computable optimality certificates and accelerated convergence guarantees for convex optimization problems, suitable for scenarios requiring verifiable solutions.",
        "idea_spark": {
            "transferable": "The primal-dual averaging framework can be transferred to game theory and market dynamics analysis.",
            "idea": "Use multiple averages to balance primal-dual asymmetries and achieve acceleration.",
            "risk": "Two-average methods preserve symmetry but lose certificate guarantees, requiring three averages to recover convergence.",
            "inspiration": "Interpret gradient extrapolation method as a dual three-average accelerated method, establishing algorithm correspondences."
        }
    }
}

